package com.google.gson.reflect;
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.TypeVariable;
import java.util.HashMap;
import java.util.Map;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.$Gson$Types;
import java.lang.reflect.GenericArrayType;
import java.lang.reflect.Type;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;

class TypeTokenTest {

  @Test
  void testGetArray_withNormalType_invokesArrayOfAndReturnsTypeToken() throws Exception {
    Type componentType = String.class;

    try (MockedStatic<$Gson$Types> mockedStatic = mockStatic($Gson$Types.class)) {
      GenericArrayType arrayType = mock(GenericArrayType.class);
      mockedStatic.when(() -> $Gson$Types.arrayOf(componentType)).thenReturn(arrayType);

      // Use reflection to invoke the private constructor
      TypeToken<?> result = createTypeToken(arrayType);

      mockedStatic.verify(() -> $Gson$Types.arrayOf(componentType));
      assertNotNull(result);
      assertEquals(arrayType, result.getType());
    }
  }

  @Test
  void testGetArray_withNullType_invokesArrayOfAndReturnsTypeToken() throws Exception {
    Type componentType = null;

    try (MockedStatic<$Gson$Types> mockedStatic = mockStatic($Gson$Types.class)) {
      GenericArrayType arrayType = mock(GenericArrayType.class);
      mockedStatic.when(() -> $Gson$Types.arrayOf(componentType)).thenReturn(arrayType);

      // Use reflection to invoke the private constructor
      TypeToken<?> result = createTypeToken(arrayType);

      mockedStatic.verify(() -> $Gson$Types.arrayOf(componentType));
      assertNotNull(result);
      assertEquals(arrayType, result.getType());
    }
  }

  private static TypeToken<?> createTypeToken(Type type) throws Exception {
    var ctor = TypeToken.class.getDeclaredConstructor(Type.class);
    ctor.setAccessible(true);
    return (TypeToken<?>) ctor.newInstance(type);
  }
}
